import{_ as i,o as s,c as a,a0 as r}from"./chunks/framework.DTwdCQre.js";const k=JSON.parse('{"title":"API Errors","description":"How to read and resolve errors from LLM providers (Anthropic, OpenAI, and compatible).","frontmatter":{"title":"API Errors","description":"How to read and resolve errors from LLM providers (Anthropic, OpenAI, and compatible)."},"headers":[],"relativePath":"troubleshooting/api-errors.md","filePath":"troubleshooting/api-errors.md","lastUpdated":1777632127000}'),t={name:"troubleshooting/api-errors.md"};function o(n,e,d,l,h,p){return s(),a("div",null,[...e[0]||(e[0]=[r(`<h1 id="api-errors" tabindex="-1">API Errors <a class="header-anchor" href="#api-errors" aria-label="Permalink to &quot;API Errors&quot;">​</a></h1><p>This page covers error types returned by LLM providers and what to do when something goes wrong.</p><h2 id="error-classification" tabindex="-1">Error Classification <a class="header-anchor" href="#error-classification" aria-label="Permalink to &quot;Error Classification&quot;">​</a></h2><p>Errors are normalized into categories in <code>internal/provider/errors.go</code>:</p><table tabindex="0"><thead><tr><th>Kind</th><th>HTTP Status</th><th>Meaning</th></tr></thead><tbody><tr><td><code>auth</code></td><td>401, 403</td><td>Authentication or permission failure.</td></tr><tr><td><code>rate_limit</code></td><td>429</td><td>Too many requests.</td></tr><tr><td><code>invalid_request</code></td><td>400, 422</td><td>Malformed request payload.</td></tr><tr><td><code>server</code></td><td>500+</td><td>Temporary provider-side failure.</td></tr><tr><td><code>timeout</code></td><td>(none)</td><td>Request exceeded deadline.</td></tr><tr><td><code>network</code></td><td>(none)</td><td>DNS, dial, or connection failure.</td></tr></tbody></table><h2 id="authentication-errors" tabindex="-1">Authentication Errors <a class="header-anchor" href="#authentication-errors" aria-label="Permalink to &quot;Authentication Errors&quot;">​</a></h2><p><strong>Message</strong>: <code>Invalid API key. Please check your ANTHROPIC_API_KEY.</code></p><p>Causes: missing key (<code>ErrAPIKeyRequired</code> from <code>internal/config</code>), wrong format (Anthropic keys start with <code>sk-ant-</code>), expired or revoked key.</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $ANTHROPIC_API_KEY                      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># verify set</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> \${ANTHROPIC_API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">7}                </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># check prefix</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;x-api-key: </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ANTHROPIC_API_KEY</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  https://api.anthropic.com/v1/models</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # test directly</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><strong>Message</strong>: <code>API access denied. Check your API key permissions.</code></p><p>The key exists but lacks scope for the requested resource. Regenerate with correct permissions at the provider console.</p><h2 id="rate-limiting-429" tabindex="-1">Rate Limiting (429) <a class="header-anchor" href="#rate-limiting-429" aria-label="Permalink to &quot;Rate Limiting (429)&quot;">​</a></h2><p><strong>Message</strong>: <code>Rate limited. Retrying automatically...</code></p><p>The application retries automatically with exponential backoff (from <code>internal/api/client.go</code>):</p><ul><li>3 retries with delays of 1s, 2s, 4s.</li><li>After all retries fail: <code>request failed after 3 retries: rate_limit_exceeded</code>.</li></ul><p>Reduce concurrent usage or upgrade your provider plan.</p><h2 id="server-errors-5xx" tabindex="-1">Server Errors (5xx) <a class="header-anchor" href="#server-errors-5xx" aria-label="Permalink to &quot;Server Errors (5xx)&quot;">​</a></h2><p><strong>Message</strong>: <code>Server error. Please try again later.</code></p><p>Retried automatically (same 3-attempt backoff). If persistent, check the provider status page or switch models with <code>/model</code>.</p><h2 id="timeout-errors" tabindex="-1">Timeout Errors <a class="header-anchor" href="#timeout-errors" aria-label="Permalink to &quot;Timeout Errors&quot;">​</a></h2><p><strong>Message</strong>: <code>provider request timed out</code></p><p>The HTTP client timeout is 5 minutes (from <code>internal/api/client.go</code>). Try a faster model or check your network connection.</p><h2 id="invalid-request-400-422" tabindex="-1">Invalid Request (400, 422) <a class="header-anchor" href="#invalid-request-400-422" aria-label="Permalink to &quot;Invalid Request (400, 422)&quot;">​</a></h2><p><strong>Message format</strong>: <code>Invalid provider request (status): body</code></p><p>Causes: context length exceeded, invalid model name, malformed schema. If <code>context_length_exceeded</code>, use <code>/compact</code>.</p><h2 id="reading-provider-errors" tabindex="-1">Reading Provider Errors <a class="header-anchor" href="#reading-provider-errors" aria-label="Permalink to &quot;Reading Provider Errors&quot;">​</a></h2><p>Errors from the Anthropic HTTP client are classified by <code>classifyError()</code> in <code>internal/api/client.go</code>. Provider adapters in <code>internal/provider/anthropic</code> and <code>internal/provider/openai</code> add a second classification layer:</p><div class="language-go vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">func</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ClassifyHTTPStatus</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">statusCode</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">body</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ClassifiedError</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">func</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ClassifyError</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">err</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> error</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ClassifiedError</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>OpenAI-compatible providers transform their error payloads into the same categories before reaching the agent loop.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./common-issues.html">Common Issues</a> — API key setup, connection issues</li><li><a href="./../architecture/providers.html">Provider Configuration</a> — Provider setup</li></ul>`,31)])])}const u=i(t,[["render",o]]);export{k as __pageData,u as default};
